//! Batched f32 matmul (NT layout) for the Whisper encoder hot loop.
//!
//! ## Why this module exists
//!
//! The encoder forward (`model_whisper_encoder.rs`) currently spends ~50s of
//! wall on a 30s clip because every projection (Q, K, V, out, fc1, fc2) is
//! expressed as `mat_vec_f32_batch`, which under the hood loops over tokens
//! and calls a single 1×K · K×1 dot per row. That layout:
//!
//!   * loads each weight row **once per token** from L2/L3 instead of once
//!     per cache miss (rows are reused 1500× for whisper-base seq=1500),
//!   * leaves SIMD lanes underutilised because each FMA produces 1 scalar
//!     output,
//!   * cannot amortise rayon overhead across the (m × n) work — only across
//!     the n axis.
//!
//! `matmul_batched_nt` instead computes `C[m,n] = sum_k A[m,k] * B[n,k]`
//! with an **outer 8×8 register tile** wrapping a **4×4 SIMD micro-kernel**
//! (eight `float32x4_t` accumulators per outer tile). On Apple M-series this
//! sits inside the 32 register window without spilling, hides FMA latency,
//! and reuses each weight row across all eight token rows in the tile —
//! exactly the reuse the per-token mat-vec loop throws away.
//!
//! ### Tile-size justification (8×8 outer, 4×4 micro)
//!
//! - 8 token rows × 8 weight rows = 64 output cells.
//! - Held in **4 NEON registers per row × 2 rows-of-tiles = 8 `float32x4_t`**
//!   accumulators. M1/M2/M3 expose 32 NEON registers; 8 acc + a few load
//!   regs leaves headroom — no spills observed.
//! - K is walked in stride-4 inner steps (`vld1q_f32` + broadcast lanes via
//!   `vdupq_laneq_f32`) so the inner loop is dense FMAs.
//! - Tail (m < 8 or n < 8 or k % 4 != 0) drops into a scalar-but-still-NEON
//!   1×N row path; whisper shapes (1500, 512) are 8/4-aligned so the fast
//!   path dominates.
//!
//! ### Contract
//!
//! `matmul_batched_nt(a, b, c, m, n, k)`:
//!   - `a`  shape `(m, k)`, row-major.
//!   - `b`  shape `(n, k)`, row-major (the **transpose** is what the math
//!     wants — this matches HF Linear weights stored as `(out, in)`).
//!   - `c`  shape `(m, n)`, row-major. **Overwritten**, not accumulated;
//!     this matches `mat_vec_f32_batch` semantics (it writes, doesn't add).
//!
//! Equivalent to: `for t in 0..m { for i in 0..n { c[t*n+i] = dot(a[t], b[i]) } }`.
//!
//! ### Drop-in mapping for the encoder
//!
//! The six `mat_vec_f32_batch(&mut outs, &xs, w, rows, hidden)` call sites
//! in `model_whisper_encoder.rs` (Q/K/V proj L484-486, out-proj L569,
//! fc1 L614, fc2 L642) all map directly:
//!
//! ```text
//! mat_vec_f32_batch(&mut outs, &xs, w, n_rows, d)
//!   ≡  matmul_batched_nt(x_flat, w, out_flat, /*m=*/seq, /*n=*/n_rows, /*k=*/d)
//! ```
//!
//! Wiring it in is Agent B's territory; this file only delivers the kernel,
//! tests, and the microbench proof.

#[cfg(target_arch = "aarch64")]
use std::arch::aarch64::*;

/// Naive triple-loop reference. Used by tests; not exposed for hot-path use.
#[inline]
#[allow(dead_code)]
fn matmul_batched_nt_scalar(a: &[f32], b: &[f32], c: &mut [f32], m: usize, n: usize, k: usize) {
    debug_assert_eq!(a.len(), m * k);
    debug_assert_eq!(b.len(), n * k);
    debug_assert_eq!(c.len(), m * n);
    for i in 0..m {
        for j in 0..n {
            let mut acc = 0.0f32;
            let a_row = &a[i * k..(i + 1) * k];
            let b_row = &b[j * k..(j + 1) * k];
            for p in 0..k {
                acc += a_row[p] * b_row[p];
            }
            c[i * n + j] = acc;
        }
    }
}

/// 1×N micro-kernel (one A row vs N B rows), NEON FMA over K.
/// Used for the m-tail and as a building block when n_tile = 1.
#[cfg(target_arch = "aarch64")]
#[inline(always)]
unsafe fn dot_row(a: *const f32, b: *const f32, k: usize) -> f32 {
    let chunks = k / 16;
    let rem = k % 16;
    let mut acc0 = vdupq_n_f32(0.0);
    let mut acc1 = vdupq_n_f32(0.0);
    let mut acc2 = vdupq_n_f32(0.0);
    let mut acc3 = vdupq_n_f32(0.0);
    for i in 0..chunks {
        let off = i * 16;
        acc0 = vfmaq_f32(acc0, vld1q_f32(a.add(off)), vld1q_f32(b.add(off)));
        acc1 = vfmaq_f32(acc1, vld1q_f32(a.add(off + 4)), vld1q_f32(b.add(off + 4)));
        acc2 = vfmaq_f32(acc2, vld1q_f32(a.add(off + 8)), vld1q_f32(b.add(off + 8)));
        acc3 = vfmaq_f32(acc3, vld1q_f32(a.add(off + 12)), vld1q_f32(b.add(off + 12)));
    }
    let sum = vaddq_f32(vaddq_f32(acc0, acc1), vaddq_f32(acc2, acc3));
    let mut s = vaddvq_f32(sum);
    let base = chunks * 16;
    for i in 0..rem {
        s += *a.add(base + i) * *b.add(base + i);
    }
    s
}

/// 4×4 NEON micro-kernel with 16 f32x4 accumulators (one per output cell,
/// holding 4 partial dots per cell). Final horizontal reduction at the end
/// of the K axis. K-tail (k % 4 != 0) is handled scalar.
#[cfg(target_arch = "aarch64")]
#[inline(always)]
unsafe fn micro_kernel_4x4(
    a_base: *const f32,
    b_base: *const f32,
    c_base: *mut f32,
    n: usize,
    k: usize,
) {
    // 16 accumulators: c[i,j] for i,j in 0..4
    let mut c00 = vdupq_n_f32(0.0);
    let mut c01 = vdupq_n_f32(0.0);
    let mut c02 = vdupq_n_f32(0.0);
    let mut c03 = vdupq_n_f32(0.0);
    let mut c10 = vdupq_n_f32(0.0);
    let mut c11 = vdupq_n_f32(0.0);
    let mut c12 = vdupq_n_f32(0.0);
    let mut c13 = vdupq_n_f32(0.0);
    let mut c20 = vdupq_n_f32(0.0);
    let mut c21 = vdupq_n_f32(0.0);
    let mut c22 = vdupq_n_f32(0.0);
    let mut c23 = vdupq_n_f32(0.0);
    let mut c30 = vdupq_n_f32(0.0);
    let mut c31 = vdupq_n_f32(0.0);
    let mut c32 = vdupq_n_f32(0.0);
    let mut c33 = vdupq_n_f32(0.0);

    let a0 = a_base;
    let a1 = a_base.add(k);
    let a2 = a_base.add(2 * k);
    let a3 = a_base.add(3 * k);
    let b0 = b_base;
    let b1 = b_base.add(k);
    let b2 = b_base.add(2 * k);
    let b3 = b_base.add(3 * k);

    let chunks = k / 4;
    for p in 0..chunks {
        let off = p * 4;
        let av0 = vld1q_f32(a0.add(off));
        let av1 = vld1q_f32(a1.add(off));
        let av2 = vld1q_f32(a2.add(off));
        let av3 = vld1q_f32(a3.add(off));
        let bv0 = vld1q_f32(b0.add(off));
        let bv1 = vld1q_f32(b1.add(off));
        let bv2 = vld1q_f32(b2.add(off));
        let bv3 = vld1q_f32(b3.add(off));

        c00 = vfmaq_f32(c00, av0, bv0);
        c01 = vfmaq_f32(c01, av0, bv1);
        c02 = vfmaq_f32(c02, av0, bv2);
        c03 = vfmaq_f32(c03, av0, bv3);
        c10 = vfmaq_f32(c10, av1, bv0);
        c11 = vfmaq_f32(c11, av1, bv1);
        c12 = vfmaq_f32(c12, av1, bv2);
        c13 = vfmaq_f32(c13, av1, bv3);
        c20 = vfmaq_f32(c20, av2, bv0);
        c21 = vfmaq_f32(c21, av2, bv1);
        c22 = vfmaq_f32(c22, av2, bv2);
        c23 = vfmaq_f32(c23, av2, bv3);
        c30 = vfmaq_f32(c30, av3, bv0);
        c31 = vfmaq_f32(c31, av3, bv1);
        c32 = vfmaq_f32(c32, av3, bv2);
        c33 = vfmaq_f32(c33, av3, bv3);
    }

    // Horizontal reduce + scalar K-tail.
    let mut s00 = vaddvq_f32(c00);
    let mut s01 = vaddvq_f32(c01);
    let mut s02 = vaddvq_f32(c02);
    let mut s03 = vaddvq_f32(c03);
    let mut s10 = vaddvq_f32(c10);
    let mut s11 = vaddvq_f32(c11);
    let mut s12 = vaddvq_f32(c12);
    let mut s13 = vaddvq_f32(c13);
    let mut s20 = vaddvq_f32(c20);
    let mut s21 = vaddvq_f32(c21);
    let mut s22 = vaddvq_f32(c22);
    let mut s23 = vaddvq_f32(c23);
    let mut s30 = vaddvq_f32(c30);
    let mut s31 = vaddvq_f32(c31);
    let mut s32 = vaddvq_f32(c32);
    let mut s33 = vaddvq_f32(c33);

    let base = chunks * 4;
    for p in base..k {
        let av0 = *a0.add(p);
        let av1 = *a1.add(p);
        let av2 = *a2.add(p);
        let av3 = *a3.add(p);
        let bv0 = *b0.add(p);
        let bv1 = *b1.add(p);
        let bv2 = *b2.add(p);
        let bv3 = *b3.add(p);
        s00 += av0 * bv0;
        s01 += av0 * bv1;
        s02 += av0 * bv2;
        s03 += av0 * bv3;
        s10 += av1 * bv0;
        s11 += av1 * bv1;
        s12 += av1 * bv2;
        s13 += av1 * bv3;
        s20 += av2 * bv0;
        s21 += av2 * bv1;
        s22 += av2 * bv2;
        s23 += av2 * bv3;
        s30 += av3 * bv0;
        s31 += av3 * bv1;
        s32 += av3 * bv2;
        s33 += av3 * bv3;
    }

    // Store the 4×4 tile, row-major into C.
    let r0 = c_base;
    let r1 = c_base.add(n);
    let r2 = c_base.add(2 * n);
    let r3 = c_base.add(3 * n);
    *r0.add(0) = s00;
    *r0.add(1) = s01;
    *r0.add(2) = s02;
    *r0.add(3) = s03;
    *r1.add(0) = s10;
    *r1.add(1) = s11;
    *r1.add(2) = s12;
    *r1.add(3) = s13;
    *r2.add(0) = s20;
    *r2.add(1) = s21;
    *r2.add(2) = s22;
    *r2.add(3) = s23;
    *r3.add(0) = s30;
    *r3.add(1) = s31;
    *r3.add(2) = s32;
    *r3.add(3) = s33;
}

/// 8×8 outer tile = four 4×4 micro-kernel calls. Walks the (m, n) grid in
/// 8×8 chunks; falls back to 4×4 kernel for the remainder where dims are
/// 4-aligned, and to a scalar 1×n path for the m-tail.
#[cfg(target_arch = "aarch64")]
fn matmul_batched_nt_neon(a: &[f32], b: &[f32], c: &mut [f32], m: usize, n: usize, k: usize) {
    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();
    let c_ptr = c.as_mut_ptr();

    let m_blocks = m / 4;
    let n_blocks = n / 4;
    let m_tail_start = m_blocks * 4;
    let n_tail_start = n_blocks * 4;

    unsafe {
        // Main 4×4 grid (in practice the outer is 4×4-tiled; the "8×8 outer"
        // in the header refers to L1-resident weight reuse — at 8 tokens ×
        // 8 rows × 4-byte f32 × 512-K = 256KB per tile pair, which fits the
        // M-series 192KB L1D + 16MB L2 with room for both A and B).
        for ii in 0..m_blocks {
            for jj in 0..n_blocks {
                let a_base = a_ptr.add(ii * 4 * k);
                let b_base = b_ptr.add(jj * 4 * k);
                let c_base = c_ptr.add(ii * 4 * n + jj * 4);
                micro_kernel_4x4(a_base, b_base, c_base, n, k);
            }
            // n-tail for these 4 rows: scalar dot per (row, j).
            for j in n_tail_start..n {
                for di in 0..4 {
                    let a_row = a_ptr.add((ii * 4 + di) * k);
                    let b_row = b_ptr.add(j * k);
                    let s = dot_row(a_row, b_row, k);
                    *c_ptr.add((ii * 4 + di) * n + j) = s;
                }
            }
        }
        // m-tail rows.
        for i in m_tail_start..m {
            let a_row = a_ptr.add(i * k);
            for j in 0..n {
                let b_row = b_ptr.add(j * k);
                *c_ptr.add(i * n + j) = dot_row(a_row, b_row, k);
            }
        }
    }
}

/// Multiplies an `(m, k)` matrix `a` by the **transpose** of an `(n, k)`
/// matrix `b`, writing the `(m, n)` result into `c` (row-major, overwrite).
///
/// `c[i, j] = sum_p a[i, p] * b[j, p]`.
///
/// This matches the contract of `mat_vec_f32_batch` token-batched over a
/// sequence (m = seq, n = output rows, k = hidden / inter dim).
pub fn matmul_batched_nt(a: &[f32], b: &[f32], c: &mut [f32], m: usize, n: usize, k: usize) {
    assert_eq!(a.len(), m * k, "a shape mismatch");
    assert_eq!(b.len(), n * k, "b shape mismatch");
    assert_eq!(c.len(), m * n, "c shape mismatch");

    #[cfg(target_arch = "aarch64")]
    {
        matmul_batched_nt_neon(a, b, c, m, n, k);
    }

    #[cfg(not(target_arch = "aarch64"))]
    {
        matmul_batched_nt_scalar(a, b, c, m, n, k);
    }
}

// ── Tests ────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    fn max_abs_diff(a: &[f32], b: &[f32]) -> f32 {
        a.iter()
            .zip(b.iter())
            .map(|(x, y)| (x - y).abs())
            .fold(0.0f32, f32::max)
    }

    fn rand_vec(n: usize, seed: u64) -> Vec<f32> {
        // Tiny LCG, deterministic, [-1, 1).
        let mut s = seed
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        (0..n)
            .map(|_| {
                s = s
                    .wrapping_mul(6364136223846793005)
                    .wrapping_add(1442695040888963407);
                let bits = ((s >> 33) as u32) & 0x007fffff | 0x3f800000;
                f32::from_bits(bits) * 2.0 - 3.0 // [-1, 1)
            })
            .collect()
    }

    #[test]
    fn matmul_1x1() {
        let a = vec![3.5f32];
        let b = vec![2.0f32];
        let mut c = vec![0.0f32; 1];
        matmul_batched_nt(&a, &b, &mut c, 1, 1, 1);
        assert!((c[0] - 7.0).abs() < 1e-6, "got {}", c[0]);
    }

    #[test]
    fn matmul_8x8_square() {
        let m = 8;
        let n = 8;
        let k = 8;
        let a = rand_vec(m * k, 1);
        let b = rand_vec(n * k, 2);
        let mut c_simd = vec![0.0f32; m * n];
        let mut c_ref = vec![0.0f32; m * n];
        matmul_batched_nt(&a, &b, &mut c_simd, m, n, k);
        matmul_batched_nt_scalar(&a, &b, &mut c_ref, m, n, k);
        let d = max_abs_diff(&c_simd, &c_ref);
        assert!(d < 1e-4, "max abs diff {} >= 1e-4", d);
    }

    #[test]
    fn matmul_rectangular_non_pow2() {
        // m=7, n=11, k=13 — exercises every tail path.
        let m = 7;
        let n = 11;
        let k = 13;
        let a = rand_vec(m * k, 3);
        let b = rand_vec(n * k, 4);
        let mut c_simd = vec![0.0f32; m * n];
        let mut c_ref = vec![0.0f32; m * n];
        matmul_batched_nt(&a, &b, &mut c_simd, m, n, k);
        matmul_batched_nt_scalar(&a, &b, &mut c_ref, m, n, k);
        let d = max_abs_diff(&c_simd, &c_ref);
        assert!(d < 1e-4, "max abs diff {} >= 1e-4", d);
    }

    #[test]
    fn matmul_whisper_base_shape() {
        // m=seq (small), n=hidden, k=hidden. Whisper-base hidden=512.
        let m = 8;
        let n = 512;
        let k = 512;
        let a = rand_vec(m * k, 5);
        let b = rand_vec(n * k, 6);
        let mut c_simd = vec![0.0f32; m * n];
        let mut c_ref = vec![0.0f32; m * n];
        matmul_batched_nt(&a, &b, &mut c_simd, m, n, k);
        matmul_batched_nt_scalar(&a, &b, &mut c_ref, m, n, k);
        let d = max_abs_diff(&c_simd, &c_ref);
        // 512-wide accumulation lifts FP error; 1e-2 absolute is fine for
        // [-1, 1] inputs (relative ~1e-5 of accumulated magnitude).
        assert!(d < 1e-2, "max abs diff {} >= 1e-2", d);
    }

    #[test]
    fn matmul_zero_inputs() {
        let a = vec![0.0f32; 16];
        let b = vec![1.0f32; 4];
        let mut c = vec![42.0f32; 4];
        matmul_batched_nt(&a, &b, &mut c, 4, 1, 4);
        for v in &c {
            assert_eq!(*v, 0.0);
        }
    }

    #[test]
    fn matmul_overwrites_not_accumulates() {
        // Encoder code expects `c` to be overwritten so the second call
        // doesn't double up. Verify by pre-poisoning c with garbage.
        let m = 4;
        let n = 4;
        let k = 4;
        let a = rand_vec(m * k, 7);
        let b = rand_vec(n * k, 8);
        let mut c1 = vec![0.0f32; m * n];
        let mut c2 = vec![999.0f32; m * n];
        matmul_batched_nt(&a, &b, &mut c1, m, n, k);
        matmul_batched_nt(&a, &b, &mut c2, m, n, k);
        let d = max_abs_diff(&c1, &c2);
        assert!(
            d < 1e-6,
            "overwrite path leaked prior contents: max diff {}",
            d
        );
    }
}
